import { useState, useEffect } from "react";
import { useParams, useNavigate, Link } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import API from "../api/axios";

const EditPostPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user, loading } = useAuth();

  const [title, setTitle] = useState("");
  const [body, setBody] = useState("");
  const [image, setImage] = useState(null);
  const [preview, setPreview] = useState("");
  const [error, setError] = useState("");
  const [saving, setSaving] = useState(false);
  const [fetching, setFetching] = useState(true);

  const [darkMode, setDarkMode] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem("user-theme");
    setDarkMode(saved === "dark");
  }, []);

  useEffect(() => {
    const fetchPost = async () => {
      try {
        const res = await API.get(`/posts/${id}`);
        setTitle(res.data.title);
        setBody(res.data.body);
        setPreview(
          res.data.image
            ? `http://localhost:5000/uploads/${res.data.image}`
            : ""
        );
      } catch {
        setError("Failed to load post.");
      } finally {
        setFetching(false);
      }
    };

    fetchPost();
  }, [id]);

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    setImage(file);
    if (file) setPreview(URL.createObjectURL(file));
  };

  const handleUpdate = async (e) => {
    e.preventDefault();
    setSaving(true);
    setError("");

    try {
      const formData = new FormData();
      formData.append("title", title);
      formData.append("body", body);
      if (image) formData.append("image", image);

      await API.put(`/posts/${id}`, formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });

      navigate(`/post/${id}`);
    } catch {
      setError("Failed to update post.");
    } finally {
      setSaving(false);
    }
  };

  /* ================= THEME ================= */
  const theme = {
    page: {
      minHeight: "100vh",
      padding: "40px 15px",
      display: "flex",
      justifyContent: "center",
      background: darkMode
        ? "#560032"
        : "linear-gradient(135deg, #f7c6d9, #ffffff)",
    },

    container: {
      width: "100%",
      maxWidth: "850px",
    },

    header: {
      display: "flex",
      gap: "10px",
      marginBottom: "18px",
    },

    backBtn: {
      padding: "10px 14px",
      borderRadius: "20px",
      textDecoration: "none",
      fontSize: "14px",
      fontWeight: "bold",
      background: "#f7c6d9",
      color: "rgb(12, 75, 52)",
      border: "1px solid rgb(12, 75, 52)",
    },

    card: {
      background: darkMode ? "#2e091e" : "#fff",
      borderRadius: "18px",
      padding: "30px",
      boxShadow: darkMode
        ? "0 0 18px rgba(0,0,0,0.6)"
        : "0 10px 25px rgba(0,0,0,0.1)",
    },

    title: {
      textAlign: "center",
      marginBottom: "25px",
      fontSize: "22px",
      fontWeight: "700",
    },

    input: {
      width: "100%",
      padding: "12px",
      marginBottom: "14px",
      borderRadius: "10px",
      border: darkMode ? "1px solid #eb99c4" : "1px solid #ccc",
      background: darkMode ? "#f3c1df" : "#fff",
      color: darkMode ? "#141414" : "#000",
      outline: "none",
    },

    textarea: {
      width: "100%",
      height: "160px",
      padding: "12px",
      marginBottom: "14px",
      borderRadius: "10px",
      border: darkMode ? "1px solid #eb99c4" : "1px solid #ccc",
      background: darkMode ? "#f3c1df" : "#fff",
      color: darkMode ? "#fff" : "#000",
      resize: "none",
      outline: "none",
    },

    fileBox: {
      display: "flex",
      alignItems: "center",
      gap: "10px",
      marginBottom: "14px",
    },

    fileInput: {
      display: "none",
    },

    fileLabel: {
      padding: "10px 16px",
      borderRadius: "20px",
      background: darkMode ? "#f7c6d9" : "#1a4120",
      color: darkMode ? "#000" : "#fff",
      cursor: "pointer",
      fontWeight: "bold",
      display: "inline-block",
    },

    previewBox: {
      marginTop: "10px",
      borderRadius: "14px",
      overflow: "hidden",
      border: darkMode ? "1px solid #333" : "1px solid #eee",
    },

    preview: {
      width: "100%",
      maxHeight: "320px",
      objectFit: "cover",
      display: "block",
    },

    button: {
      width: "100%",
      padding: "13px",
      marginTop: "18px",
      borderRadius: "22px",
      border: "none",
      background: saving ? "#999" : "#1a4120",
      color: "#fff",
      fontWeight: "bold",
      cursor: saving ? "not-allowed" : "pointer",
    },

    error: {
      background: "#ff4d6d",
      color: "#fff",
      padding: "10px",
      borderRadius: "10px",
      marginBottom: "15px",
      textAlign: "center",
    },
  };

  if (loading || fetching) {
    return <div style={{ textAlign: "center", padding: "50px" }}>Loading...</div>;
  }

  if (!user) {
    return (
      <div style={{ textAlign: "center", padding: "50px", color: "red" }}>
        Unauthorized access
      </div>
    );
  }

  return (
    <div style={theme.page}>
      <div style={theme.container}>

        {/* HEADER */}
        <div style={theme.header}>
          <Link to="/home" style={theme.backBtn}>⬅ Back Home</Link>
        </div>

        {/* CARD */}
        <div style={theme.card}>
          <div style={theme.title}>✏️ Edit Post</div>

          {error && <div style={theme.error}>{error}</div>}

          <form onSubmit={handleUpdate}>

            <input
              type="text"
              placeholder="Post title"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              style={theme.input}
              required
            />

            <textarea
              placeholder="Write your post..."
              value={body}
              onChange={(e) => setBody(e.target.value)}
              style={theme.textarea}
              required
            />

            {/* FILE UPLOAD */}
            <div style={theme.fileBox}>
              <label htmlFor="fileUpload" style={theme.fileLabel}>
                📁 Choose Image
              </label>

              <input
                id="fileUpload"
                type="file"
                onChange={handleImageChange}
                style={theme.fileInput}
              />
            </div>

            {/* PREVIEW */}
            {preview && (
              <div style={theme.previewBox}>
                <img src={preview} alt="preview" style={theme.preview} />
              </div>
            )}

            {/* BUTTON */}
            <button type="submit" disabled={saving} style={theme.button}>
              {saving ? "Updating..." : "Update Post"}
            </button>

          </form>
        </div>

      </div>
    </div>
  );
};

export default EditPostPage;
